import { compareVersions } from "./impl";
import { test, expect } from "vitest";

test("compareVersions catches target bugs", () => {
  // r1_prerelease_equal_tags_ignored: different prerelease tags should be ordered
  expect(compareVersions("1.0.0-alpha", "1.0.0-beta")).toBe(-1);
  expect(compareVersions("1.0.0-beta", "1.0.0-alpha")).toBe(1);
  expect(compareVersions("1.0.0-rc.1", "1.0.0-rc.2")).toBe(-1);

  // r1_min_instead_of_max_loop: extra trailing parts must be compared
  expect(compareVersions("1.0.1", "1.0")).toBe(1);
  expect(compareVersions("1.0", "1.0.1")).toBe(-1);
  expect(compareVersions("2.0.0.1", "2.0.0")).toBe(1);

  // r1_radix_dropped_parseInt: leading zeros must not be treated as octal
  expect(compareVersions("1.08", "1.8")).toBe(0);
  expect(compareVersions("1.09", "1.9")).toBe(0);
  expect(compareVersions("1.010", "1.10")).toBe(0);

  // r1_prerelease_detection_via_split_only: prerelease in any segment must be detected
  expect(compareVersions("1.0-alpha.0", "1.0.0")).toBe(-1);
  expect(compareVersions("1.0.0", "1.0-alpha.0")).toBe(1);
  expect(compareVersions("1.0-x.0", "1.0.0")).toBe(-1);

